async function run() {
  info('Parsing issue body ...')

  let content = getInput('body')

  if (content === '' && Object.hasOwn(github_context.payload, 'issue')) {
    content = github_context.payload.issue.body
  }

  try {
    const parsedContent = await parseMD(content)

    if (parsedContent !== undefined) {
      setOutput('data', parsedContent)
    } else {
      setFailed(`There was no valid payload found in the issue.`)
    }
  } catch (err) {
    setFailed(err)
  }
}

run()

